import React, { useState } from 'react';
import MessageBubble from './MessageBubble';
import agentClient from '../ag-ui/agentClient';

const AGENTS = [
  { key: 'session', label: '📅 Sessions' },
  { key: 'faq', label: '❓ FAQ' },
  { key: 'personalized', label: '✨ Personalized' }
];

const ChatWindow = () => {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [currentAgent, setCurrentAgent] = useState('session');

  const sendMessage = async () => {
    if (!input.trim()) return;
    setMessages([...messages, { sender: 'user', text: input }]);
    const res = await agentClient(input, currentAgent);
    setMessages(msgs => [...msgs, { sender: 'agent', text: res }]);
    setInput('');
  };

  return (
    <div style={{ maxWidth: 500, margin: '0 auto' }}>
      <div style={{ display: 'flex', gap: 8, marginBottom: 12 }}>
        {AGENTS.map(agent => (
          <button
            key={agent.key}
            onClick={() => setCurrentAgent(agent.key)}
            style={{
              padding: '8px 16px',
              borderRadius: 20,
              border: currentAgent === agent.key ? '2px solid #0078d4' : '1px solid #ccc',
              background: currentAgent === agent.key ? '#e3f2fd' : '#f1f1f1',
              fontWeight: currentAgent === agent.key ? 700 : 400,
              cursor: 'pointer'
            }}
          >
            {agent.label}
          </button>
        ))}
      </div>
      <div style={{ minHeight: 300, border: '1px solid #ccc', padding: 10, marginBottom: 10 }}>
        {messages.map((msg, i) => <MessageBubble key={i} sender={msg.sender} text={msg.text} />)}
      </div>
      <input value={input} onChange={e => setInput(e.target.value)} style={{ width: '80%' }} />
      <button onClick={sendMessage}>Send</button>
    </div>
  );
};

export default ChatWindow;
